def main():
    mod = 10**9 + 7
    n, a, b = map(int, input().split())
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, n + 1):
        if i == a or i == b:
            continue
        dp[i] = (dp[i - 1] + dp[i - 2]) % mod
    print(dp[n])

if __name__ == '__main__':
    main()
